                    <svg width='12' height='12' viewBox='0 0 24 24' fill='none' stroke='currentColor' strokeWidth='1.5' strokeLinecap='round'>
                      <path d='M19 12H5M12 5l-7 7 7 7' />
                    </svg>
                    {content.backLabel}
                  </button>
                  <button
                    className='btn-primary'
                    onClick={() => {
                      if (validateShippingStep()) setStep('payment');
