                        <path d='M12 3a9 9 0 1 1-9 9' />
                      </svg>
                      <div>
                        <p style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 300, color: 'var(--fg)', marginBottom: '0.5rem' }}>
                          {blikPendingTitle}
                        </p>
                        <p className='type-label' style={{ color: 'var(--muted)', maxWidth: '320px' }}>
                          {blikPendingBody}
                        </p>
