                    clientSecret={stripeClientSecret}
                    initiating={stripeInitiating}
                    error={stripeError}
                    total={total}
                    checkoutItemsEmpty={checkoutItems.length === 0}
                    elementsReady={stripeElementsReady}
                    onInitiate={() => {
                      handleInitiateStripePayment().catch(() => undefined);
