              </div>

              <div className='mb-12'>
                <div className='type-label mb-5' style={{ color: 'var(--accent)' }}>
                  {content.info.directEyebrow}
                </div>
                <div
                  className='flex flex-col gap-2'
                  style={{
                    fontFamily: 'var(--font-body)',
                    fontSize: '0.875rem',
                    fontWeight: 300,
                    color: 'var(--muted)',
